+        deployWorkspace?: typeof deployWorkspaceForCommitFlow;
+        createReview?: typeof createReviewForCommitFlow;
+        streamReviewEvents?: typeof streamReviewEventsForCommitFlow;
+        getReview?: typeof getReviewForCommitFlow;
