+            severityThreshold: options?.severityThreshold ?? 'low',
+            maxFindings: options?.maxFindings,
+            includeProvenance: options?.includeProvenance ?? true,
+            includeValidationEvidence: options?.includeValidationEvidence ?? true,
+          },
+          model: options?.model,
