+    p.log.info(`Streaming review events for ${reviewId}`);
+    let terminalStatus: string | null = null;
+    await streamReviewEventsForCommitFlow(workerUrl, reviewId, async (event) => {
+      const line = formatEvent(event);
+      if (line) {
